import socket
import network
import time
import json
import ubinascii
import uhashlib
import ustruct
from machine import Pin

# WiFi credentials
WIFI_SSID = "your_wifi_ssid"
WIFI_PASSWORD = "your_wifi_password"

# Initialize LED pin
led = Pin(2, Pin.OUT)

# Connect to WiFi
def connect_wifi():
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    wlan.connect(WIFI_SSID, WIFI_PASSWORD)
    
    while not wlan.isconnected():
        time.sleep(1)
    
    print("Connected to WiFi")
    print("IP address:", wlan.ifconfig()[0])

# WebSocket handshake
def websocket_handshake(client_socket):
    headers = {}
    while True:
        line = client_socket.readline().decode().strip()
        if not line:
            break
        if ':' in line:
            key, value = line.split(':', 1)
            headers[key.lower()] = value.strip()
    
    if 'upgrade' not in headers or headers['upgrade'].lower() != 'websocket':
        return False
    
    if 'connection' not in headers or 'upgrade' not in headers['connection'].lower():
        return False
    
    # Generate WebSocket accept key
    key = headers['sec-websocket-key']
    accept_key = ubinascii.b2a_base64(
        uhashlib.sha1(key.encode() + b"258EAFA5-E914-47DA-95CA-C5AB0DC85B11").digest()
    ).decode().strip()
    
    # Send handshake response
    response = (
        "HTTP/1.1 101 Switching Protocols\r\n"
        "Upgrade: websocket\r\n"
        "Connection: Upgrade\r\n"
        "Sec-WebSocket-Accept: " + accept_key + "\r\n\r\n"
    )
    
    client_socket.send(response.encode())
    return True

# WebSocket frame decoding
def decode_websocket_frame(data):
    if len(data) < 2:
        return None
    
    # Parse frame header
    fin = (data[0] & 0x80) != 0
    opcode = data[0] & 0x0F
    mask = (data[1] & 0x80) != 0
    payload_len = data[1] & 0x7F
    
    # Parse payload length
    if payload_len == 126:
        payload_len = ustruct.unpack("!H", data[2:4])[0]
        offset = 4
    elif payload_len == 127:
        payload_len = ustruct.unpack("!Q", data[2:10])[0]
        offset = 10
    else:
        offset = 2
    
    # Parse mask
    if mask:
        mask_key = data[offset:offset+4]
        offset += 4
    else:
        mask_key = None
    
    # Extract payload
    payload = data[offset:offset+payload_len]
    
    # Unmask payload if needed
    if mask_key:
        payload = bytearray(payload)
        for i in range(len(payload)):
            payload[i] ^= mask_key[i % 4]
        payload = bytes(payload)
    
    return payload.decode('utf-8')

# Send WebSocket message
def send_websocket_message(client_socket, message):
    frame = bytearray()
    frame.append(0x81)  # FIN + TEXT opcode
    payload_len = len(message)
    
    if payload_len <= 125:
        frame.append(payload_len)
    elif payload_len <= 65535:
        frame.append(126)
        frame.extend(ustruct.pack("!H", payload_len))
    else:
        frame.append(127)
        frame.extend(ustruct.pack("!Q", payload_len))
    
    frame.extend(message.encode('utf-8'))
    client_socket.send(frame)

# Process JSON command
def process_command(command):
    try:
        data = json.loads(command)
        action = data.get('action', '')
        
        if action == 'turn_on':
            led.on()
            return {"status": "success", "message": "LED turned on"}
        elif action == 'turn_off':
            led.off()
            return {"status": "success", "message": "LED turned off"}
        elif action == 'toggle':
            led.value(not led.value())
            return {"status": "success", "message": "LED toggled"}
        else:
            return {"status": "error", "message": "Unknown action"}
    except Exception as e:
        return {"status": "error", "message": str(e)}

# Main server function
def start_websocket_server():
    connect_wifi()
    
    # Create socket
    server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    server_socket.bind(('0.0.0.0', 80))
    server_socket.listen(1)
    
    print("WebSocket server listening on port 80")
    
    while True:
        client_socket, addr = server_socket.accept()
        print("Client connected from", addr)
        
        try:
            # Perform WebSocket handshake
            if not websocket_handshake(client_socket):
                client_socket.close()
                continue
            
            # Handle messages
            while True:
                try:
                    data = client_socket.recv(1024)
                    if not data:
                        break
                    
                    # Decode WebSocket frame
                    message = decode_websocket_frame(data)
                    if message:
                        print("Received:", message)
                        
                        # Process command
                        response = process_command(message)
                        
                        # Send response
                        send_websocket_message(client_socket, json.dumps(response))
                        
                except Exception as e:
                    print("Error:", e)
                    break
                    
        except Exception as e:
            print("Client error:", e)
        finally:
            client_socket.close()

# Start the server
start_websocket_server()